.appear {
    position:relative;
    animation-name:for0;
    animation-duration:1s;
    opacity: 0;
    animation-fill-mode: forwards;
}

@-webkit-keyframes for0
{
    0%   {opacity: 0;left:20px;}
    100% {opacity: 1;left:0px;}
}

.appear-a {
    position:relative;
    animation-name:for1;
    animation-duration:1s;
    opacity: 0;
    animation-fill-mode: forwards;
}

@-webkit-keyframes for1
{
    0%   {opacity: 0;top:20px;}
    100% {opacity: 1;top:0px;}
}

.appear-b {
    position:relative;
    animation-name:for2;
    animation-duration:1s;
    opacity: 0;
    animation-fill-mode: forwards;
}

@-webkit-keyframes for2
{
    0%   {opacity: 0;left:60px;}
    100% {opacity: 1;left:0px;}
}

.appear-c {
    position:relative;
    animation-name:for3;
    animation-duration:1s;
    opacity: 0;
    animation-fill-mode: forwards;
}

@-webkit-keyframes for3
{
    0%   {opacity: 0;right:60px;}
    100% {opacity: 1;right:0px;}
}

.disappear {
    position:relative;
    animation-name:for4;
    animation-duration:1s;
    opacity: 0;
    animation-fill-mode: forwards;
}

@-webkit-keyframes for4
{
    0%   {opacity: 1;right:0px;}
    98% {opacity: 0;right:100px;width: auto;height: auto;}
    99% {opacity: 0;}
    100% {opacity: 0;width: 0;height: 0;}
}
